import type { FC } from 'react';
import React from 'react';
import type { GenerateConfig } from '../generate';
import type { PickerType, TimePickerProps } from '../interface';
import type { SharedPickerProps } from '..';
import Picker from '..';

export default function generateSinglePicker<DateType>(generateConfig: GenerateConfig<DateType>) {
  function getPicker<InnerPickerProps extends SharedPickerProps<DateType>>(picker: PickerType, displayName?: string) {
    const BasePicker: FC<InnerPickerProps> = props => (
      <Picker {...props} picker={picker} generateConfig={generateConfig} />
    );

    if (displayName) {
      BasePicker.displayName = displayName;
    }

    return BasePicker;
  }

  type OmitTypes<Props> = Omit<Props, 'picker' | 'generateConfig'>;

  const TimePicker = getPicker<OmitTypes<TimePickerProps<DateType>>>('time', 'TimePicker');

  return {
    TimePicker,
  };
}
